cat > /tmp/apply_patch.js << 'NODESCRIPT'
const fs = require('fs');
const file = 'src/browser.ts';
let content = fs.readFileSync(file, 'utf8');

const oldImport = "import {puppeteer} from './third_party/index.js';";
const newImport = "import puppeteer from 'puppeteer-core';";

if (content.includes(oldImport)) {
    content = content.replace(oldImport, newImport);
    fs.writeFileSync(file, content);
    console.log('Replaced import successfully');
} else {
    console.log('Old import not found, skipping');
    process.exit(1);
}
NODESCRIPT
node /tmp/apply_patch.js

